import { useState, useEffect } from "react";
import "../styles/mainmenu/LeagueMenu.css";

function LeagueMenu() {
    const [jornadas, setJornadas] = useState([]);
    const [jornadaActual, setJornadaActual] = useState(0);
    const [modalVisible, setModalVisible] = useState(false);

    useEffect(() => {
        const equiposAlmacenados = JSON.parse(localStorage.getItem("equipos"));
        const equiposAleatorios = mezclarEquipos(equiposAlmacenados);
    
        const clasificacionInicial = equiposAleatorios.map((equipo) => ({
            id: equipo.id,
            nombre: equipo.nombre,
            puntos: 0,
            partidosJugados: 0,
            victorias: 0,
            empates: 0,
            derrotas: 0,
            golesFavor: 0,
            golesContra: 0,
            diferenciaGoles: 0,
        }));
        setClasificacion(clasificacionInicial);
    
        const jornadas = generarJornadasLiga([...equiposAleatorios]);
        setCalendario(jornadas);
    
        localStorage.setItem("clasificacion", JSON.stringify(clasificacionInicial));
        localStorage.setItem("calendario", JSON.stringify(jornadas));
    }, []);

    const abrirModal = () => {
        setModalVisible(true);
    };

    const cerrarModal = () => {
        setModalVisible(false);
    };

    const siguienteJornada = () => {
        if (jornadaActual < jornadas.length - 1) {
            setJornadaActual(jornadaActual + 1);
        }
    };

    const anteriorJornada = () => {
        if (jornadaActual > 0) {
            setJornadaActual(jornadaActual - 1);
        }
    };

    return (
        <div className="league-menu">
            <h1>League Menu</h1>
            <div className="jornada-preview-container" onClick={abrirModal}>
                <h2>Jornada {jornadaActual + 1}</h2>
                <div className="jornada-preview">
                    {jornadas[jornadaActual]?.slice(0, 5).map((partido, index) => (
                        <div key={index} className="partido-preview">
                            <div className="equipo">
                                <img
                                    src={partido.local.imagen}
                                    alt={partido.local.nombre}
                                    className="escudo"
                                />
                                <span>{partido.local.nombre}</span>
                            </div>
                            <span className="vs">vs</span>
                            <div className="equipo">
                                <img
                                    src={partido.visitante.imagen}
                                    alt={partido.visitante.nombre}
                                    className="escudo"
                                />
                                <span>{partido.visitante.nombre}</span>
                            </div>
                        </div>
                    ))}
                </div>
            </div>

            {modalVisible && (
                <div className="modal-overlay" onClick={cerrarModal}>
                    <div
                        className="modal-content"
                        onClick={(e) => e.stopPropagation()} // Evitar cerrar al hacer clic dentro del modal
                    >
                        <h2>Jornada {jornadaActual + 1}</h2>
                        <div className="jornada-detalle">
                            {jornadas[jornadaActual]?.map((partido, index) => (
                                <div key={index} className="partido">
                                    <div className="equipo">
                                        <img
                                            src={partido.local.imagen}
                                            alt={partido.local.nombre}
                                            className="escudo"
                                        />
                                        <span>{partido.local.nombre}</span>
                                    </div>
                                    <span className="vs">vs</span>
                                    <div className="equipo">
                                        <img
                                            src={partido.visitante.imagen}
                                            alt={partido.visitante.nombre}
                                            className="escudo"
                                        />
                                        <span>{partido.visitante.nombre}</span>
                                    </div>
                                </div>
                            ))}
                        </div>
                        <div className="navegacion-jornadas">
                            <button onClick={anteriorJornada} disabled={jornadaActual === 0}>
                                ⬅ Anterior
                            </button>
                            <button
                                onClick={siguienteJornada}
                                disabled={jornadaActual === jornadas.length - 1}
                            >
                                Siguiente ➡
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

export default LeagueMenu;
